            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                filterSongs(s.toString(), adapter)
            }
            override fun afterTextChanged(s: android.text.Editable?) {}
        })
    }

    private fun filterSongs(query: String, adapter: SongAdapter) {
        filteredSongList.clear()
        filteredSongPaths.clear()
        for (i in songList.indices) {
            if (songList[i].lowercase().contains(query.lowercase())) {
                filteredSongList.add(songList[i])
                filteredSongPaths.add(songPaths[i])
            }
        }
        adapter.notifyItemRangeChanged(0, adapter.itemCount)
    }

    private fun setupLibraryView() {
        val rvLiked = findViewById<RecyclerView>(R.id.rvLikedSongs)
        rvLiked.layoutManager = LinearLayoutManager(this)

        val likedSongs = ArrayList<String>()
        val likedPaths = ArrayList<String>()
        for (i in songPaths.indices) {
            if (likedSongPaths.contains(songPaths[i])) {
                likedSongs.add(songList[i])
                likedPaths.add(songPaths[i])
            }
        }

        val likedAdapter = SongAdapter(likedSongs, { position ->
            MusicPlayerManager.currentSongList = likedSongs
            MusicPlayerManager.currentSongPaths = likedPaths
            MusicPlayerManager.playSong(this, position)
            startActivity(Intent(this, PlayerActivity::class.java))
        }, { position, isLiked ->
            if (!isLiked) {
                likedSongPaths.remove(likedPaths[position])
                setupLibraryView()
            }
        })
        rvLiked.adapter = likedAdapter

        val rvPlaylists = findViewById<RecyclerView>(R.id.rvPlaylists)
        rvPlaylists.layoutManager = LinearLayoutManager(this)
        val playlistAdapter = PlaylistAdapter(playlists, { playlist ->
            MusicPlayerManager.currentSongList = playlist.songPaths
            MusicPlayerManager.currentSongPaths = playlist.songPaths
            if (playlist.songPaths.isNotEmpty()) {
                MusicPlayerManager.playSong(this, 0)
                startActivity(Intent(this, PlayerActivity::class.java))
            }
        })
        rvPlaylists.adapter = playlistAdapter
    }
}

package com.example.musicplayer

import android.content.Context
import android.media.MediaPlayer
import android.net.Uri

object MusicPlayerManager {
    private var mediaPlayer: MediaPlayer? = null
    var currentSongList: List<String> = emptyList()
    var currentSongPaths: List<String> = emptyList()
    var currentPosition: Int = -1
    var isShuffle: Boolean = false
    var isRepeat: Boolean = false

    var onSongChanged: ((Int) -> Unit)? = null
    var onPlaybackStatusChanged: ((Boolean) -> Unit)? = null

    fun playSong(context: Context, position: Int) {
        if (currentSongPaths.isEmpty() || position < 0 || position >= currentSongPaths.size) return

        currentPosition = position
        mediaPlayer?.stop()
        mediaPlayer?.release()

        mediaPlayer = MediaPlayer().apply {
            setDataSource(context, Uri.parse(currentSongPaths[position]))
            prepare()
            isLooping = isRepeat
            start()
            setOnCompletionListener {
                playNext(context)
            }
        }
        onSongChanged?.invoke(position)
        onPlaybackStatusChanged?.invoke(true)
    }

    fun playNext(context: Context) {
        if (currentSongPaths.isEmpty()) return
        val nextPos = if (isShuffle) {
            (currentSongPaths.indices).random()
        } else {
            (currentPosition + 1) % currentSongPaths.size
        }
        playSong(context, nextPos)
    }

    fun playPrevious(context: Context) {
        if (currentSongPaths.isEmpty()) return
        val prevPos = if (currentPosition - 1 < 0) currentSongPaths.size - 1 else currentPosition - 1
        playSong(context, prevPos)
    }

    fun togglePlayPause() {
        mediaPlayer?.let {
            if (it.isPlaying) {
                it.pause()
                onPlaybackStatusChanged?.invoke(false)
            } else {
                it.start()
                onPlaybackStatusChanged?.invoke(true)
            }
        }
    }

    fun isPlaying(): Boolean = mediaPlayer?.isPlaying ?: false

    fun getMediaPlayer(): MediaPlayer? = mediaPlayer

    fun getCurrentSongName(): String? {
        return if (currentPosition in currentSongList.indices) currentSongList[currentPosition] else null
    }
}

package com.example.musicplayer

import android.content.Context
import android.media.MediaPlayer
import android.net.Uri

object MusicPlayerManager {
    private var mediaPlayer: MediaPlayer? = null
    var currentSongList: List<String> = emptyList()
    var currentSongPaths: List<String> = emptyList()
    var currentPosition: Int = -1
    var isShuffle: Boolean = false
    var isRepeat: Boolean = false

    var onSongChanged: ((Int) -> Unit)? = null
    var onPlaybackStatusChanged: ((Boolean) -> Unit)? = null

    fun playSong(context: Context, position: Int) {
        if (currentSongPaths.isEmpty() || position < 0 || position >= currentSongPaths.size) return

        currentPosition = position
        mediaPlayer?.stop()
        mediaPlayer?.release()

        mediaPlayer = MediaPlayer().apply {
            setDataSource(context, Uri.parse(currentSongPaths[position]))
            prepare()
            isLooping = isRepeat
            start()
            setOnCompletionListener {
                playNext(context)
            }
        }
        onSongChanged?.invoke(position)
        onPlaybackStatusChanged?.invoke(true)
    }

    fun playNext(context: Context) {
        if (currentSongPaths.isEmpty()) return
        val nextPos = if (isShuffle) {
            (currentSongPaths.indices).random()
        } else {
            (currentPosition + 1) % currentSongPaths.size
        }
        playSong(context, nextPos)
    }

    fun playPrevious(context: Context) {
        if (currentSongPaths.isEmpty()) return
        val prevPos = if (currentPosition - 1 < 0) currentSongPaths.size - 1 else currentPosition - 1
        playSong(context, prevPos)
    }

    fun togglePlayPause() {
        mediaPlayer?.let {
            if (it.isPlaying) {
                it.pause()
                onPlaybackStatusChanged?.invoke(false)
            } else {
                it.start()
                onPlaybackStatusChanged?.invoke(true)
            }
        }
    }

    fun getMediaPlayer(): MediaPlayer? = mediaPlayer

    fun getCurrentSongName(): String? {
        return if (currentPosition in currentSongList.indices) currentSongList[currentPosition] else null
    }

    fun release() {
        mediaPlayer?.release()
        mediaPlayer = null
    }
}

package com.example.musicplayer

import android.os.Bundle
import android.os.Handler
import android.os.Looper
import android.widget.ImageButton
import android.widget.SeekBar
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity
import java.util.Locale

class PlayerActivity : AppCompatActivity() {

    private lateinit var tvSongName: TextView
    private lateinit var tvCurrentTime: TextView
    private lateinit var tvTotalTime: TextView
    private lateinit var btnPlay: ImageButton
    private lateinit var btnNext: ImageButton
    private lateinit var btnPrev: ImageButton
    private lateinit var btnShuffle: ImageButton
    private lateinit var btnRepeat: ImageButton
    private lateinit var seekBar: SeekBar

    private val handler = Handler(Looper.getMainLooper())
    private val updateSeekBar = object : Runnable {
        override fun run() {
            MusicPlayerManager.getMediaPlayer()?.let {
                if (it.isPlaying) {
                    seekBar.progress = it.currentPosition
                    tvCurrentTime.text = formatTime(it.currentPosition)
                }
            }
            handler.postDelayed(this, 1000)
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_player)

        tvSongName = findViewById(R.id.tvSongName)
        tvCurrentTime = findViewById(R.id.tvCurrentTime)
        tvTotalTime = findViewById(R.id.tvTotalTime)
        btnPlay    = findViewById(R.id.btnPlay)
        btnNext    = findViewById(R.id.btnNext)
        btnPrev    = findViewById(R.id.btnPrev)
        btnShuffle = findViewById(R.id.btnShuffle)
        btnRepeat  = findViewById(R.id.btnRepeat)
        seekBar    = findViewById(R.id.seekBar)

        updateUI()

        btnPlay.setOnClickListener {
            MusicPlayerManager.togglePlayPause()
        }

        btnNext.setOnClickListener {
            MusicPlayerManager.playNext(this)
        }

        btnPrev.setOnClickListener {
            MusicPlayerManager.playPrevious(this)
        }

        btnShuffle.setOnClickListener {
            MusicPlayerManager.isShuffle = !MusicPlayerManager.isShuffle
            updateToggleColors()
        }

        btnRepeat.setOnClickListener {
            MusicPlayerManager.isRepeat = !MusicPlayerManager.isRepeat
            MusicPlayerManager.getMediaPlayer()?.isLooping = MusicPlayerManager.isRepeat
            updateToggleColors()
        }

        MusicPlayerManager.onSongChanged = {
            updateUI()
        }

        MusicPlayerManager.onPlaybackStatusChanged = { isPlaying ->
            btnPlay.setImageResource(if (isPlaying) android.R.drawable.ic_media_pause else android.R.drawable.ic_media_play)
        }

        seekBar.setOnSeekBarChangeListener(object : SeekBar.OnSeekBarChangeListener {
            override fun onProgressChanged(seekBar: SeekBar?, progress: Int, fromUser: Boolean) {
                if (fromUser) {
                    MusicPlayerManager.getMediaPlayer()?.seekTo(progress)
                    tvCurrentTime.text = formatTime(progress)
                }
            }
            override fun onStartTrackingTouch(seekBar: SeekBar?) {}
            override fun onStopTrackingTouch(seekBar: SeekBar?) {}
        })

        handler.post(updateSeekBar)
    }

    private fun updateUI() {
        tvSongName.text = MusicPlayerManager.getCurrentSongName()
        MusicPlayerManager.getMediaPlayer()?.let {
            seekBar.max = it.duration
            tvTotalTime.text = formatTime(it.duration)
            btnPlay.setImageResource(if (it.isPlaying) android.R.drawable.ic_media_pause else android.R.drawable.ic_media_play)
        }
        updateToggleColors()
    }

    private fun updateToggleColors() {
        val activeColor = android.graphics.Color.parseColor("#1DB954")
        val inactiveColor = android.graphics.Color.parseColor("#B3B3B3")

        btnShuffle.setColorFilter(if (MusicPlayerManager.isShuffle) activeColor else inactiveColor)
        btnRepeat.setColorFilter(if (MusicPlayerManager.isRepeat) activeColor else inactiveColor)
    }

    private fun formatTime(milliseconds: Int): String {
        val minutes = (milliseconds / 1000) / 60
        val seconds = (milliseconds / 1000) % 60
        return String.format(Locale.getDefault(), "%d:%02d", minutes, seconds)
    }

    override fun onDestroy() {
        super.onDestroy()
        handler.removeCallbacks(updateSeekBar)
    }
}

